// 智能内容分析和页面类型判断
const content = $input.first().json;
const url = $('输入参数设置').first().json.url;
const sceneCount = parseInt($('输入参数设置').first().json.scene_count);
const videoStyle = $('输入参数设置').first().json.video_style;
const voiceLanguage = $('输入参数设置').first().json.voice_language;

// 提取和清理文本内容
function cleanText(text) {
  if (!text) return '';
  return text.replace(/\s+/g, ' ').replace(/[\r\n]+/g, ' ').trim();
}

// 判断页面类型
function detectPageType(url, title, content) {
  const urlLower = url.toLowerCase();
  const titleLower = (title || '').toLowerCase();
  const contentLower = content.toLowerCase();

  // 电商平台检测
  const ecommercePatterns = [
    'amazon', 'taobao', 'tmall', 'jd.com', 'shopify', 'alibaba',
    'ebay', 'walmart', 'target', 'bestbuy', '购买', '商品', 'product',
    'shop', 'store', 'buy', 'price', '$', '¥', '€', '£'
  ];

  // 新闻平台检测
  const newsPatterns = [
    'news', 'article', 'report', 'breaking', '新闻', '报道', 
    'headline', 'story', 'press', 'media', '今日', '昨日'
  ];

  let ecommerceScore = 0;
  let newsScore = 0;

  ecommercePatterns.forEach(pattern => {
    if (urlLower.includes(pattern) || titleLower.includes(pattern) || contentLower.includes(pattern)) {
      ecommerceScore++;
    }
  });

  newsPatterns.forEach(pattern => {
    if (urlLower.includes(pattern) || titleLower.includes(pattern) || contentLower.includes(pattern)) {
      newsScore++;
    }
  });

  if (ecommerceScore > newsScore) return 'ecommerce';
  if (newsScore > ecommerceScore) return 'news';
  return 'general';
}

// 提取关键信息
const title = cleanText(content.title);
const description = cleanText(content.description);
const price = cleanText(content.price);
const features = cleanText(content.features);
const fullContent = cleanText(content.content);

// 判断页面类型
const pageType = detectPageType(url, title, fullContent);

// 根据页面类型生成不同的提示词
let extractionPrompt = '';
let videoPrompt = '';

if (pageType === 'ecommerce') {
  extractionPrompt = `请分析以下电商商品页面内容，提取关键信息：

标题：${title}
描述：${description}
价格：${price}
特性：${features}

请提取以下信息并以JSON格式返回：
1. 产品名称 (product_name)
2. 主要特性 (main_features) - 数组格式
3. 价格信息 (price_info)
4. 目标用户 (target_audience)
5. 产品优势 (advantages) - 数组格式
6. 使用场景 (use_cases) - 数组格式`;

  videoPrompt = `创建一个${sceneCount}个分镜的${videoStyle}风格商品介绍视频脚本。
视频目标：推广产品，吸引购买
语言：${voiceLanguage}
分镜要求：每个分镜5秒，包含画面描述和配音文案`;

} else if (pageType === 'news') {
  extractionPrompt = `请分析以下新闻页面内容，提取关键信息：

标题：${title}
内容：${fullContent.substring(0, 2000)}

请提取以下信息并以JSON格式返回：
1. 新闻标题 (news_title)
2. 主要事件 (main_event)
3. 关键人物 (key_people) - 数组格式
4. 时间地点 (time_location)
5. 重要细节 (important_details) - 数组格式
6. 影响分析 (impact_analysis)`;

  videoPrompt = `创建一个${sceneCount}个分镜的${videoStyle}风格新闻报道视频脚本。
视频目标：客观报道新闻，传递信息
语言：${voiceLanguage}
分镜要求：每个分镜5秒，包含画面描述和配音文案`;

} else {
  extractionPrompt = `请分析以下网页内容，提取关键信息：

标题：${title}
描述：${description}
内容：${fullContent.substring(0, 2000)}

请提取以下信息并以JSON格式返回：
1. 主题 (main_topic)
2. 关键点 (key_points) - 数组格式
3. 目标受众 (target_audience)
4. 核心信息 (core_message)
5. 相关细节 (related_details) - 数组格式`;

  videoPrompt = `创建一个${sceneCount}个分镜的${videoStyle}风格内容介绍视频脚本。
语言：${voiceLanguage}
分镜要求：每个分镜5秒，包含画面描述和配音文案`;
}

return {
  page_type: pageType,
  url: url,
  raw_content: {
    title: title,
    description: description,
    price: price,
    features: features,
    content: fullContent.substring(0, 3000) // 限制长度
  },
  extraction_prompt: extractionPrompt,
  video_prompt: videoPrompt,
  scene_count: sceneCount,
  video_style: videoStyle,
  voice_language: voiceLanguage
};

// 生成分镜脚本
const extractedInfo = $input.first().json.message.content;
const analysisData = $('内容分析与类型判断').first().json;

let structuredInfo;
try {
  // 尝试解析AI提取的结构化信息
  structuredInfo = JSON.parse(extractedInfo);
} catch (error) {
  // 如果解析失败，创建默认结构
  structuredInfo = {
    main_topic: analysisData.raw_content.title || '内容主题',
    key_points: ['要点1', '要点2', '要点3']
  };
}

// 根据页面类型和提取的信息生成分镜脚本提示词
const pageType = analysisData.page_type;
const sceneCount = analysisData.scene_count;
const videoStyle = analysisData.video_style;
const voiceLanguage = analysisData.voice_language;

let scriptPrompt = '';

if (pageType === 'ecommerce') {
  scriptPrompt = `基于以下商品信息，创建${sceneCount}个分镜的${videoStyle}风格商品推广视频脚本：

商品信息：${JSON.stringify(structuredInfo, null, 2)}

要求：
1. 每个分镜5秒时长
2. 包含详细的画面描述和配音文案
3. 风格：${videoStyle}
4. 语言：${voiceLanguage}
5. 适合亚马逊等平台推广
6. 突出产品优势和使用场景

请按以下JSON格式返回：
{
  "scenes": [
    {
      "scene_number": 1,
      "duration": 5,
      "visual_description": "画面描述",
      "narration": "配音文案",
      "camera_movement": "镜头运动",
      "style_notes": "风格说明"
    }
  ]
}`;
} else if (pageType === 'news') {
  scriptPrompt = `基于以下新闻信息，创建${sceneCount}个分镜的${videoStyle}风格新闻报道视频脚本：

新闻信息：${JSON.stringify(structuredInfo, null, 2)}

要求：
1. 每个分镜5秒时长
2. 包含详细的画面描述和配音文案
3. 风格：${videoStyle}
4. 语言：${voiceLanguage}
5. 客观真实的新闻报道风格
6. 逻辑清晰，信息完整

请按以下JSON格式返回：
{
  "scenes": [
    {
      "scene_number": 1,
      "duration": 5,
      "visual_description": "画面描述",
      "narration": "配音文案",
      "camera_movement": "镜头运动",
      "style_notes": "风格说明"
    }
  ]
}`;
} else {
  scriptPrompt = `基于以下内容信息，创建${sceneCount}个分镜的${videoStyle}风格视频脚本：

内容信息：${JSON.stringify(structuredInfo, null, 2)}

要求：
1. 每个分镜5秒时长
2. 包含详细的画面描述和配音文案
3. 风格：${videoStyle}
4. 语言：${voiceLanguage}
5. 内容吸引人，传达核心信息

请按以下JSON格式返回：
{
  "scenes": [
    {
      "scene_number": 1,
      "duration": 5,
      "visual_description": "画面描述",
      "narration": "配音文案",
      "camera_movement": "镜头运动",
      "style_notes": "风格说明"
    }
  ]
}`;
}

return {
  script_prompt: scriptPrompt,
  extracted_info: structuredInfo,
  page_type: pageType,
  scene_count: sceneCount,
  video_style: videoStyle,
  voice_language: voiceLanguage,
  original_url: analysisData.url
};

// 解析分镜脚本并准备图像生成
const scriptResponse = $input.first().json.message.content;
const previousData = $('生成分镜脚本提示词').first().json;

let scenes;
try {
  const scriptData = JSON.parse(scriptResponse);
  scenes = scriptData.scenes || [];
} catch (error) {
  // 如果解析失败，创建默认分镜
  console.log('Script parsing failed, creating default scenes');
  const sceneCount = previousData.scene_count;
  scenes = [];
  for (let i = 1; i <= sceneCount; i++) {
    scenes.push({
      scene_number: i,
      duration: 5,
      visual_description: `分镜${i}的画面描述`,
      narration: `分镜${i}的配音文案`,
      camera_movement: "稳定镜头",
      style_notes: previousData.video_style
    });
  }
}

// 为每个分镜准备图像生成提示词
const imagePrompts = scenes.map(scene => {
  const styleMapping = {
    '专业商务': 'professional business style, clean corporate aesthetic, high-quality product photography',
    '活泼轻松': 'vibrant and playful style, bright colors, energetic composition',
    '高端奢华': 'luxury premium style, elegant sophisticated aesthetic, high-end fashion photography',
    '简约现代': 'minimalist modern style, clean lines, contemporary design'
  };

  const stylePrompt = styleMapping[previousData.video_style] || 'professional style';

  return {
    scene_number: scene.scene_number,
    image_prompt: `${scene.visual_description}, ${stylePrompt}, cinematic lighting, 4K quality, detailed`,
    narration: scene.narration,
    duration: scene.duration,
    camera_movement: scene.camera_movement,
    style_notes: scene.style_notes
  };
});

return {
  scenes: imagePrompts,
  total_scenes: imagePrompts.length,
  video_style: previousData.video_style,
  voice_language: previousData.voice_language,
  page_type: previousData.page_type,
  original_url: previousData.original_url,
  extracted_info: previousData.extracted_info
};

// 处理图像生成成功的情况
const imageData = $input.first().binary;
const sceneData = $('分镜处理循环').first().json;
const retryCount = parseInt($node['输入参数设置'].json.retry_count) || 0;

return {
  scene_number: sceneData.scene_number,
  image_data: imageData,
  narration: sceneData.narration,
  duration: sceneData.duration,
  camera_movement: sceneData.camera_movement,
  status: 'success',
  retry_count: retryCount,
  image_prompt: sceneData.image_prompt
};

// 处理图像生成失败的情况
const sceneData = $('分镜处理循环').first().json;
const retryCount = parseInt($node['输入参数设置'].json.retry_count) || 0;

if (retryCount >= 3) {
  // 超过3次重试，返回错误
  return {
    scene_number: sceneData.scene_number,
    status: 'failed',
    retry_count: retryCount,
    error: 'Maximum retry attempts reached',
    image_prompt: sceneData.image_prompt
  };
}

// 准备重试
return {
  scene_number: sceneData.scene_number,
  status: 'retry',
  retry_count: retryCount + 1,
  image_prompt: sceneData.image_prompt,
  narration: sceneData.narration,
  duration: sceneData.duration,
  camera_movement: sceneData.camera_movement
};

// 收集完成的分镜数据
const sceneData = $input.first().json;
const videoResult = $node['获取视频结果'].json;
const audioData = $input.first().binary;

return {
  scene_number: sceneData.scene_number,
  video_url: videoResult.video_url || videoResult.url,
  audio_data: audioData,
  narration: sceneData.narration,
  duration: sceneData.duration,
  status: 'completed'
};

// 生成最终视频合成指令
const allScenes = $input.all();
const projectData = $node['准备图像生成'].json;

// 过滤成功的分镜
const successfulScenes = allScenes.filter(scene => scene.json.status === 'completed');
const failedScenes = allScenes.filter(scene => scene.json.status === 'failed');

if (successfulScenes.length === 0) {
  return {
    status: 'error',
    message: '所有分镜生成失败',
    failed_count: failedScenes.length
  };
}

// 按场景编号排序
successfulScenes.sort((a, b) => a.json.scene_number - b.json.scene_number);

// 准备视频合成数据
const videoSegments = successfulScenes.map(scene => ({
  scene_number: scene.json.scene_number,
  video_url: scene.json.video_url,
  audio_data: scene.binary,
  duration: scene.json.duration
}));


const summary = {
  total_scenes: projectData.total_scenes,
  successful_scenes: successfulScenes.length,
  failed_scenes: failedScenes.length,
  success_rate: (successfulScenes.length / projectData.total_scenes * 100).toFixed(2) + '%',
  original_url: projectData.original_url,
  page_type: projectData.page_type,
  video_style: projectData.video_style,
  voice_language: projectData.voice_language
};

return {
  status: 'ready_for_composition',
  video_segments: videoSegments,
  summary: summary,
  timestamp: new Date().toISOString()
};

